// Human-readable ChangeLog value for a seeded row (rule 3 — audit every insert).
const rowLabel = (row) => row.code || row.name || row.ruleType || row.label || row.userType || String(row.ID)

/**
 * Idempotent runtime seeding of the Model Builder configuration tables.
 * Existing rows — including admin-edited seed rows — are never updated or
 * deleted; only seed UUIDs that are absent get inserted. Each table's inserts
 * are captured in ChangeLog under one batch. Returns { inserted, perTable }.
 */
async function ensureModelBuilderSeed (db, { changedBy = 'system' } = {}) {
  const batchId = cds.utils.uuid()
  let inserted = 0
  const perTable = {}
  for (const table of TABLES) {
    const rows = SEED[table] || []
    const existing = await db.run(SELECT.from(NS + table).columns('ID'))
    const have = new Set((existing || []).map((r) => String(r.ID).toLowerCase()))
    const missing = rows.filter((r) => !have.has(String(r.ID).toLowerCase()))
    perTable[table] = missing.length
    if (!missing.length) continue
    await db.run(INSERT.into(NS + table).entries(missing))
    // Rule 3: ChangeLog on every CUD — one row per seeded record.
    await writeChangeLogs(db, {
      objectType: 'Lookup',
      objectId: table,
      objectName: `${table} (model-builder seed)`,
      source: 'Calibration',
      batchId,
      changedBy,
      changes: missing.map((row) => ({ fieldName: String(row.ID), oldValue: '', newValue: rowLabel(row) }))
    })
    inserted += missing.length
  }
  return { inserted, perTable }
}

module.exports = { TABLES, SEED, ensureModelBuilderSeed }
